UPDATE reservation 
SET res_status = IF(pay_no IS NOT NULL, 'DONE', 'CANCEL')
WHERE res_no = #{resNo} 
AND user_id = #{userId} 
AND NOW() > STR_TO_DATE(CONCAT(use_date, ' ', use_time), '%Y-%m-%d %H:%i:%s')

